public class RemoveDuplicates {
    public static void main(String[] args) {

        // Static input
        int[] arr = {2, 4, 4, 5, 6, 7, 8, 5};
        int n = arr.length;

        // Temporary array to store unique elements
        int[] temp = new int[n];
        int newIndex = 0;

        // Remove duplicates using nested loops
        for (int i = 0; i < n; i++) {
            boolean isDuplicate = false;

            for (int j = 0; j < newIndex; j++) {
                if (arr[i] == temp[j]) {
                    isDuplicate = true;
                    break;
                }
            }

            if (!isDuplicate) {
                temp[newIndex++] = arr[i];
            }
        }

        // Print result
        System.out.print("{");
        for (int i = 0; i < newIndex; i++) {
            System.out.print(temp[i]);
            if (i < newIndex - 1) {
                System.out.print(", ");
            }
        }
        System.out.println("}");
    }
}
